from __future__ import annotations

from datetime import datetime
from typing import Any, Dict, List, Tuple

import pandas as pd

from src.common.exception_manager import PipelineError
from src.common.pipeline_context import create_pipeline_context
from src.data_generation.generators.member_generator import run_member_generation
from src.data_generation.generators.organization_generator import run_organization_generation
from src.data_generation.generators.provider_generator import run_provider_generation
from src.data_generation.generators.facility_generator import run_facility_generation
from src.data_generation.generators.enrollment_generator import run_enrollment_generation
from src.data_generation.generators.sdoh_generator import run_sdoh_generation


MODULE_NAME = "medfabric.data_generation.orchestrator"
STEP_NAME = "Raw Layer Data Generation Pipeline"


###############################################################################
# Execution Tracking
###############################################################################

class DatasetExecutionTracker:
    """
    Track execution metrics for one generated dataset.
    """

    def __init__(self, dataset_name: str, generator_name: str):
        self.dataset_name = dataset_name
        self.generator_name = generator_name
        self.start_time: datetime = datetime.now()
        self.end_time: datetime | None = None
        self.row_count: int = 0
        self.column_count: int = 0
        self.success: bool = False
        self.error_message: str | None = None

    def complete(self, dataframe: pd.DataFrame) -> None:
        """
        Mark execution as complete using a generated dataframe.
        """

        self.end_time = datetime.now()
        self.row_count = len(dataframe)
        self.column_count = len(dataframe.columns)
        self.success = True

    def failed(self, error: Exception) -> None:
        """
        Mark execution as failed.
        """

        self.end_time = datetime.now()
        self.success = False
        self.error_message = str(error)

    def duration_seconds(self) -> float:
        """
        Return execution duration in seconds.
        """

        if self.end_time is None:
            return 0.0

        return (self.end_time - self.start_time).total_seconds()

    def to_dict(self) -> Dict[str, Any]:
        """
        Convert tracker to dictionary.
        """

        return {
            "dataset_name": self.dataset_name,
            "generator_name": self.generator_name,
            "start_time": self.start_time.isoformat(),
            "end_time": self.end_time.isoformat() if self.end_time else None,
            "duration_seconds": self.duration_seconds(),
            "row_count": self.row_count,
            "column_count": self.column_count,
            "success": self.success,
            "error_message": self.error_message,
        }


###############################################################################
# Phase 1: Foundational Entities
###############################################################################

def execute_member_generation(context, trackers: List[DatasetExecutionTracker]) -> pd.DataFrame:
    """
    Execute Member dataset generation.
    """

    logger = context.get_logger(MODULE_NAME)
    tracker = DatasetExecutionTracker("raw.members", "member_generator")
    trackers.append(tracker)

    try:
        logger.info("Starting Member generation...")
        dataframe = run_member_generation(context)
        tracker.complete(dataframe)
        logger.info("Member generation completed. Rows: %s", tracker.row_count)
        return dataframe

    except Exception as error:
        tracker.failed(error)
        logger.exception("Member generation failed.")
        raise


