###############################################################################
# Phase 2: Relationship Entities
###############################################################################

def execute_enrollment_generation(
    context,
    trackers: List[DatasetExecutionTracker],
) -> Tuple[pd.DataFrame, pd.DataFrame]:
    """
    Execute Enrollment and Member Month generation.

    Important:
        run_enrollment_generation(context) returns two dataframes:

            1. enrollment_df
            2. member_months_df

        The previous orchestrator treated that tuple as one dataframe, which
        caused:

            AttributeError: 'tuple' object has no attribute 'columns'

        This function now tracks both generated datasets separately.
    """

    logger = context.get_logger(MODULE_NAME)

    enrollment_tracker = DatasetExecutionTracker(
        "raw.enrollment",
        "enrollment_generator",
    )
    member_months_tracker = DatasetExecutionTracker(
        "raw.member_months",
        "enrollment_generator",
    )

    trackers.append(enrollment_tracker)
    trackers.append(member_months_tracker)

    try:
        logger.info("Starting Enrollment and Member Month generation...")

        result = run_enrollment_generation(context)

        if not isinstance(result, tuple) or len(result) != 2:
            raise PipelineError(
                "run_enrollment_generation must return "
                "(enrollment_df, member_months_df)."
            )

        enrollment_df, member_months_df = result

        enrollment_tracker.complete(enrollment_df)
        member_months_tracker.complete(member_months_df)

        logger.info(
            "Enrollment generation completed. Rows: %s",
            enrollment_tracker.row_count,
        )
        logger.info(
            "Member Month generation completed. Rows: %s",
            member_months_tracker.row_count,
        )

        return enrollment_df, member_months_df

    except Exception as error:
        enrollment_tracker.failed(error)
        member_months_tracker.failed(error)
        logger.exception("Enrollment / Member Month generation failed.")
        raise


